#define THREADS 256
#define WIDTH 16  
#define HEIGHT 16 
#define ETA 0.3f       
#define MOMENTUM 0.3f  

#ifndef _BACKPROP_CUDA_KERNEL_H_
#define _BACKPROP_CUDA_KERNEL_H_
#define WM(i, j)   weight_matrix[(j) + (i) * WIDTH]

#include <math.h>
#include <omp.h>
#include <stdlib.h>
#include <stdio.h>

typedef struct {
  int input_n;                  
  int hidden_n;                 
  int output_n;                 

  float *input_units;          
  float *hidden_units;         
  float *output_units;         

  float *hidden_delta;         
  float *output_delta;         

  float *target;               

  float **input_weights;       
  float **hidden_weights;      

  float **input_prev_weights;  
  float **hidden_prev_weights; 
} BPNN;

void bpnn_layerforward_omp(float *input_cuda,
	                  float *output_hidden_cuda,
					  float *input_hidden_cuda,
					  float *hidden_partial_sum,
					  int in,
					  int hid) 
{
    int by, tx, ty;
    int num_blocks = in / HEIGHT;

    // Compute partial products and store in input_hidden_cuda
    #pragma omp parallel for collapse(3) private(by, ty, tx) shared(input_cuda, input_hidden_cuda)
    for (by = 0; by < num_blocks; by++) {
        for (ty = 0; ty < HEIGHT; ty++) {
            for (tx = 0; tx < WIDTH; tx++) {
                int index =  ( hid + 1 ) * HEIGHT * by + ( hid + 1 ) * ty + tx + 1 + ( hid + 1 ) ;  
                int index_in = HEIGHT * by + ty + 1;

                float input_node_val = input_cuda[index_in];
                float weight_val = input_hidden_cuda[index];
                weight_val *= input_node_val;
                input_hidden_cuda[index] = weight_val;
            }
        }
    }

    // Reduction over ty dimension for each (by, tx)
    #pragma omp parallel for collapse(2) shared(input_hidden_cuda, hidden_partial_sum)
    for (int by = 0; by < num_blocks; by++) {
        for (int tx = 0; tx < WIDTH; tx++) {
            float sum = 0.0f;
            for (int ty = 0; ty < HEIGHT; ty++) {
                int index =  ( hid + 1 ) * HEIGHT * by + ( hid + 1 ) * ty + tx + 1 + ( hid + 1 ) ;  
                sum += input_hidden_cuda[index];
            }
            int index0 =  ( hid + 1 ) * HEIGHT * by + ( hid + 1 ) * 0 + tx + 1 + ( hid + 1 ) ;  
            input_hidden_cuda[index0] = sum;

            if (tx < hid) {
                hidden_partial_sum[by * hid + tx] = sum;
            }
        }
    }
}

void bpnn_adjust_weights_omp(float * delta,   
										 int hid,         
										float * ly,      
										 int in,          
										float * w,       
										float * oldw)  									
{
    int by, tx, ty;
    int num_blocks = in / HEIGHT;

    #pragma omp parallel for collapse(3) private(by, ty, tx) shared(delta, ly, w, oldw)
    for (by = 0; by < num_blocks; by++) {
        for (ty = 0; ty < HEIGHT; ty++) {
            for (tx = 0; tx < WIDTH; tx++) {
                int index =  ( hid + 1 ) * HEIGHT * by + ( hid + 1 ) * ty + tx + 1 + ( hid + 1 ) ;  
                int index_y = HEIGHT * by + ty + 1;
                int index_x = tx + 1;

                float new_dw = ((ETA * delta[index_x] * ly[index_y]) + (MOMENTUM * oldw[index]));
                w[index] += new_dw;
                oldw[index] = new_dw;
            }
        }
    }

    // Handle special case if ty == 0 && by == 0
    #pragma omp parallel for
    for (int index_x = 1; index_x <= WIDTH; index_x++) {
        w[index_x] += ((ETA * delta[index_x]) + (MOMENTUM * oldw[index_x]));
        oldw[index_x] = ((ETA * delta[index_x]) + (MOMENTUM * oldw[index_x]));
    }
}

void bpnn_initialize(int seed)
{
  printf("Random number generator seed: %d\n", seed);
  srand(seed);
}

float squash(float x)
{
  return (1.0f / (1.0f + expf(-x)));
}

float ABS(float x)
{
  return (x > 0.0f) ? x : -x;
}

void bpnn_layerforward(float *l1, float *l2, float **conn, int n1, int n2)
{
  int j, k;
  float sum;

  l1[0] = 1.0f;

  #pragma omp parallel for private(j, k, sum) schedule(static)
  for (j = 1; j <= n2; j++) {
    sum = 0.0f;
    for (k = 0; k <= n1; k++) {
      sum += conn[k][j] * l1[k];
    }
    l2[j] = squash(sum);
  }
}

void bpnn_output_error(float *delta, float *target, float *output, int nj, float *err)  
{
  int j;
  float o, t, errsum = 0.0f;

  #pragma omp parallel for private(j, o, t) reduction(+:errsum)
  for (j = 1; j <= nj; j++) {
    o = output[j];
    t = target[j];
    delta[j] = o * (1.0f - o) * (t - o);
    errsum += ABS(delta[j]);
  }
  *err = errsum;
}

void bpnn_hidden_error(float *delta_h,   
					   int nh, 
					   float *delta_o, 
					   int no, 
					   float **who, 
					   float *hidden, 
					   float *err)
{
  int j, k;
  float h, sum, errsum = 0.0f;

  #pragma omp parallel for private(j, k, h, sum) reduction(+:errsum)
  for (j = 1; j <= nh; j++) {
    h = hidden[j];
    sum = 0.0f;
    for (k = 1; k <= no; k++) {
      sum += delta_o[k] * who[j][k];
    }
    delta_h[j] = h * (1.0f - h) * sum;
    errsum += ABS(delta_h[j]);
  }
  *err = errsum;
}

void bpnn_adjust_weights(float *delta, int ndelta, float *ly, int nly, float **w, float **oldw)
{
  float new_dw;
  int k, j;
  ly[0] = 1.0f;

  #pragma omp parallel for private(j, k, new_dw) schedule(static)
  for (j = 1; j <= ndelta; j++) {
    for (k = 0; k <= nly; k++) {
      new_dw = ((ETA * delta[j] * ly[k]) + (MOMENTUM * oldw[k][j]));
      w[k][j] += new_dw;
      oldw[k][j] = new_dw;
    }
  }
}

BPNN *bpnn_create(int n_in, int n_hidden, int n_out)
{
  BPNN *newnet;

  newnet = (BPNN *) malloc (sizeof (BPNN));
  if (newnet == NULL) {
    printf("BPNN_CREATE: Couldn't allocate neural network\n");
    return (NULL);
  }

  newnet->input_n = n_in;
  newnet->hidden_n = n_hidden;
  newnet->output_n = n_out;
  newnet->input_units = (float *) malloc((n_in + 1) * sizeof(float));
  newnet->hidden_units = (float *) malloc((n_hidden + 1) * sizeof(float));
  newnet->output_units = (float *) malloc((n_out + 1) * sizeof(float));

  newnet->hidden_delta = (float *) malloc((n_hidden + 1) * sizeof(float));
  newnet->output_delta = (float *) malloc((n_out + 1) * sizeof(float));
  newnet->target = (float *) malloc((n_out + 1) * sizeof(float));

  newnet->input_weights = (float **) malloc((n_in + 1) * sizeof(float *));
  newnet->input_prev_weights = (float **) malloc((n_in + 1) * sizeof(float *));
  for (int i = 0; i <= n_in; i++) {
    newnet->input_weights[i] = (float *) malloc((n_hidden + 1) * sizeof(float));
    newnet->input_prev_weights[i] = (float *) malloc((n_hidden + 1) * sizeof(float));
  }

  newnet->hidden_weights = (float **) malloc((n_hidden + 1) * sizeof(float *));
  newnet->hidden_prev_weights = (float **) malloc((n_hidden + 1) * sizeof(float *));
  for (int i = 0; i <= n_hidden; i++) {
    newnet->hidden_weights[i] = (float *) malloc((n_out + 1) * sizeof(float));
    newnet->hidden_prev_weights[i] = (float *) malloc((n_out + 1) * sizeof(float));
  }

  return newnet;
}

void bpnn_free(BPNN *net)
{
  int n1 = net->input_n;
  int n2 = net->hidden_n;

  free(net->input_units);
  free(net->hidden_units);
  free(net->output_units);

  free(net->hidden_delta);
  free(net->output_delta);
  free(net->target);

  for (int i = 0; i <= n1; i++) {
    free(net->input_weights[i]);
    free(net->input_prev_weights[i]);
  }
  free(net->input_weights);
  free(net->input_prev_weights);

  for (int i = 0; i <= n2; i++) {
    free(net->hidden_weights[i]);
    free(net->hidden_prev_weights[i]);
  }
  free(net->hidden_weights);
  free(net->hidden_prev_weights);

  free(net);
}

#endif
